import { NextRequest, NextResponse } from "next/server";
import { openai, GPT_CHAT_MODEL } from "@/lib/openai";
import { translateTextStrict } from "@/lib/translate";
import { getBestsellers } from "@/lib/bestsellers";
import { supabaseAdmin } from "@/lib/supabaseAdmin";
import type { Product } from "@/types";

export const runtime = "nodejs";

// POST /api/chat
// Body: { message: string, language?: string, userId?: string }
export async function POST(req: NextRequest) {
  try {
    const { message, language, userId } = await req.json();

    if (!message || typeof message !== "string") {
      return NextResponse.json(
        { success: false, error: "Message is required." },
        { status: 400 }
      );
    }

    const userLanguage = typeof language === "string" && language.length > 0 ? language : "en";

    // 1. Translate user message to English (internal working language)
    const messageInEnglish =
      userLanguage.toLowerCase().startsWith("en")
        ? message
        : await translateTextStrict(message, "English");

    // 2. Fetch some relevant products for context
    const { data: matchedProducts } = await supabaseAdmin
      .from("products")
      .select("id, name, description, price, category")
      .ilike("name", `%${messageInEnglish}%`)
      .limit(5);

    const productsForContext = (matchedProducts ?? []) as Product[];

    // 3. Fetch bestsellers for context
    const bestsellers = await getBestsellers({ language: "en", limit: 5 });

    // 4. Build system prompt with lightweight tool-like context
    const systemPrompt = `
You are SuperMartGPT, an AI shopping assistant for an online supermarket.

You have access to:
- A product catalog (partial) with fields: id, name, description, price, category.
- The user's cart and order functions (managed by the backend, you only suggest actions).

Current matched products (may be empty):
${JSON.stringify(
  productsForContext.map((p) => ({
    id: p.id,
    name: p.name,
    price: p.price,
    category: p.category,
  }))
)}

Current bestsellers:
${JSON.stringify(
  bestsellers.map((p) => ({
    id: p.id,
    name: p.name,
    price: p.price,
    category: p.category,
  }))
)}

Instructions:
- Answer in a concise, friendly tone.
- When helpful, recommend specific products by name.
- Do not invent real brand names; use the names provided above.
- Do NOT write JSON in your reply, just natural language.`;

    // 5. Call OpenAI chat completion in English
    const completion = await openai.chat.completions.create({
      model: GPT_CHAT_MODEL,
      temperature: 0.5,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: messageInEnglish },
      ],
    });

    const replyInEnglish =
      completion.choices[0]?.message?.content?.trim() ??
      "I'm not sure how to answer that yet, but I'm learning more about our catalog every day!";

    // 6. Translate reply back to user's language
    const replyInUserLanguage = userLanguage.toLowerCase().startsWith("en")
      ? replyInEnglish
      : await translateTextStrict(replyInEnglish, userLanguage);

    // 7. Build relatedProducts in the format expected by frontend
    // Frontend expects: relatedProducts: Array<{ name: string, price: string | number }>
    const relatedProducts = productsForContext.length > 0
      ? productsForContext.map(p => ({
          name: p.name,
          price: p.price ?? 0
        }))
      : bestsellers.slice(0, 3).map(p => ({
          name: p.name,
          price: p.price ?? 0
        }));

    // 8. Shape response to match frontend expectations
    return NextResponse.json({
      success: true,
      data: {
        reply: replyInUserLanguage,
        relatedProducts,
      },
    });
  } catch (error) {
    console.error("/api/chat error", error);
    return NextResponse.json(
      { success: false, error: "Unable to generate AI response." },
      { status: 500 }
    );
  }
}
